  1	import * as React from 'react';
  2	import * as _ from 'lodash';
  3	import {
  4	  ARTIFACTHUB,
  5	  createArtifactHubTask,
  6	  updateArtifactHubTask,
  7	  useGetArtifactHubTasks,
  8	} from '../apis/artifactHub';
  9	import { TektonHubTask } from '../apis/tektonHub';
 10	import {
 11	  CatalogItem,
 12	  ExtensionHook,
 13	  ResourceIcon,
 14	  useAccessReview,
 15	  useFlag,
 16	} from '@openshift-console/dynamic-plugin-sdk';
 17	import { TaskProviders } from '../../task-quicksearch/pipeline-quicksearch-utils';
 18	import { TaskModel } from '../../../models';
 19	import { getReferenceForModel } from '../../pipelines-overview/utils';
 20	import { useTektonHubIntegration } from '../catalog-utils';
 21	import { t } from '../../utils/common-utils';
 22	import { ArtifactHubTask, FLAGS } from '../../../types';
 23	import useTasksProvider from './useTasksProvider';
 24	
 25	export const normalizeArtifactHubTasks = (
 26	  artifactHubTasks: ArtifactHubTask[],
 27	  tektonTasks: CatalogItem[],
 28	): CatalogItem<any>[] => {
 29	  return artifactHubTasks.map((task) => {
 30	    const { package_id, name, description, version } = task;
 31	    const installedTask = tektonTasks?.find(
 32	      (tektonTask) =>
 33	        tektonTask.provider === TaskProviders.artifactHub &&
 34	        tektonTask.name === name,
 35	    );
 36	    return {
 37	      uid: package_id.toString(),
 38	      type: TaskProviders.community,
 39	      name,
 40	      description,
 41	      provider: TaskProviders.artifactHub,
 42	      icon: {
 43	        node: <ResourceIcon kind={getReferenceForModel(TaskModel)} />,
 44	      },
 45	      attributes: {
 46	        installed: installedTask ? version : '',
 47	      },
 48	      cta: {
 49	        label: t('Add'),
 50	        callback: ({
 51	          selectedVersion,
 52	          selectedItem,
 53	          isDevConsoleProxyAvailable,
 54	          namespace,
 55	          callback,
 56	          setFailedTasks,
 57	        }) => {
 58	          return new Promise((resolve) => {
 59	            const selectedVersionUrl =
 60	              selectedItem?.attributes?.selectedVersionContentUrl;
 61	            if (installedTask) {
 62	              if (selectedVersion === selectedItem.attributes.installed) {
 63	                resolve(callback(installedTask.data));
 64	              } else {
 65	                resolve(
 66	                  callback({
 67	                    metadata: { name: selectedItem.data.task.name },
 68	                  }),
 69	                );
 70	                updateArtifactHubTask(
 71	                  selectedVersionUrl,
 72	                  installedTask,
 73	                  namespace,
 74	                  selectedItem.data.task.name,
 75	                  selectedVersion,
 76	                  isDevConsoleProxyAvailable,
 77	                ).catch((error) => {
 78	                  setFailedTasks((prev) => [
 79	                    ...prev,
 80	                    selectedItem.data.task.name,
 81	                  ]);
 82	                });
 83	              }
 84	            } else {
 85	              resolve(
 86	                callback({
 87	                  metadata: { name: selectedItem.data.task.name },
 88	                }),
 89	              );
 90	              createArtifactHubTask(
 91	                selectedVersionUrl,
 92	                namespace,
 93	                selectedVersion,
 94	                isDevConsoleProxyAvailable,
 95	              ).catch((error) => {
 96	                setFailedTasks((prev) => [
 97	                  ...prev,
 98	                  selectedItem.data.task.name,
 99	                ]);
100	              });
101	            }
102	          });
103	        },
104	      },
105	      data: {
106	        task,
107	        source: ARTIFACTHUB,
108	      },
109	    };
110	  });
111	};
112	
113	const useArtifactHubTasksProvider: ExtensionHook<CatalogItem[]> = ({
114	  namespace,
115	}): [CatalogItem[], boolean, string] => {
116	  const artifactHubIntegration = useTektonHubIntegration();
117	  const [tektonTasks] = useTasksProvider({});
118	  const isDevConsoleProxyAvailable = useFlag(FLAGS.DEVCONSOLE_PROXY);
119	  const canCreateTask = useAccessReview({
120	    group: TaskModel.apiGroup,
121	    resource: TaskModel.plural,
122	    namespace,
123	    verb: 'create',
124	  });
125	
126	  const canUpdateTask = useAccessReview({
127	    group: TaskModel.apiGroup,
128	    resource: TaskModel.plural,
129	    namespace,
130	    verb: 'update',
131	  });
132	
133	  const [artifactHubTasks, tasksLoaded, tasksError] = useGetArtifactHubTasks(
134	    canCreateTask && canUpdateTask && artifactHubIntegration,
135	    isDevConsoleProxyAvailable,
136	  );
137	  const normalizedArtifactHubTasks = React.useMemo<
138	    CatalogItem<TektonHubTask>[]
139	  >(
140	    () => normalizeArtifactHubTasks(artifactHubTasks, tektonTasks),
141	    [artifactHubTasks, tektonTasks],
142	  );
143	  return [normalizedArtifactHubTasks, tasksLoaded, tasksError];
144	};
145	
146	export default useArtifactHubTasksProvider;

